# Base module - defines simple base class with virtual methods
class Entity:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def get_info(self) -> str:
        return "Entity: " + self.name

    @virtual
    def get_value(self) -> int:
        return 0

    def is_active(self) -> bool:
        return True

